revision.text:
/* {{pp-template}} */
/* The TOC is hidden on Minerva (mobile skin) for width < 720px so must also hide this wrapper */
@media all and (max-width: 720px) {
	body.skin-minerva .tocright {
		display: none;
	}

	.tocright {
		width: 100% !important; /* fix the inline width while at small resolution */
	}
}
@media all and (min-width: 720px) {
	.tocright {
		float: right;
		clear: right;
		width: auto;
		margin: 0 0 0.5em 1em; 
	}

	.tocright-clear-left {
		clear: left;
	}

	.tocright-clear-both {
		clear: both;
	}

	.tocright-clear-none {
		clear: none;
	}
}

/* {{pp-template}} */
@media all and (max-width: 719px) {
	body.skin-minerva .tocright {
		display:none;
	}
}
.tocright {
	float: right;
	clear: right;
	width: auto;
	background: none;
	padding: .5em 0 .8em 1.4em;
	margin-bottom: .5em; 
}
.tocright-clear-left {
	clear: left;
}
.tocright-clear-both {
	clear: both;
}
.tocright-clear-none {
	clear: none;
}
